const body = $input.first().json.body;
const departments = body.departments || ['ceo','cto','cpo','product','rnd','design','security','legal','marketing','finance'];
const ideaPrompt = body.ideaPrompt || '';
const researchSources = body.researchSources || '';
const codebaseContext = body.codebaseContext || '';

// Create one item per department
const items = departments.map(dept => ({
  json: {
    department: dept,
    ideaPrompt,
    researchSources,
    codebaseContext,
    briefId: body.briefId
  }
}));

return items;

const dept = $json.department;
const DEPT_PROMPTS = {
  ceo: 'You are a CEO analyzing business feasibility. Sections: Business Feasibility, Market Opportunity, Competitor Analysis, Business Risks, CEO Decision (GO/NO-GO with rationale).',
  cto: 'You are a CTO evaluating technical architecture. Sections: Technical Feasibility, Proposed Architecture (include Mermaid diagram), Tech Stack, Integration Complexity, Technical Debt, Timeline.',
  cpo: 'You are a CPO defining product strategy. Sections: User Profile, USP, UX Patterns, MoSCoW Prioritization, KPIs.',
  product: 'You are a Product Manager planning features. Sections: User Stories (Gherkin format), Sprint Planning, Backlog Items, Dependencies.',
  rnd: 'You are an R&D lead researching implementation. Sections: Recommended Libraries (with trust scores), Implementation Approaches, POC Proposal, Code Samples, Dependencies.',
  design: 'You are a Design Lead. Sections: Design System Impact, Component Library, User Flows, Accessibility (WCAG), RTL Support.',
  security: 'You are a Security Analyst. Sections: Threat Model (STRIDE), OWASP Top 10, Data Classification, Auth/Authz, API Security, HIPAA/GDPR.',
  legal: 'You are a Legal Advisor. Sections: Open Source Licenses, GDPR/HIPAA, ToS Impact, Privacy Policy, IP Protection, Risk Matrix.',
  marketing: 'You are a Marketing Strategist. Sections: GTM Strategy, ICP, Competitive Positioning, Content Strategy, SEO Keywords, Launch Timeline.',
  finance: 'You are a CFO. Sections: ROI Analysis, Cost-Benefit, Unit Economics, Budget Estimate, Stage-Gate Approval, Break-even Timeline.'
};

const systemPrompt = (DEPT_PROMPTS[dept] || 'Analyze from your department perspective.') + ' Write ALL output in HEBREW. Be thorough and specific.';
const userPrompt = `Idea: ${$json.ideaPrompt}\n\nCodebase Context:\n${($json.codebaseContext || '').slice(0, 5000)}\n\nResearch Sources:\n${($json.researchSources || '').slice(0, 5000)}`;

return [{ json: { ...($json), systemPrompt, userPrompt } }];

const items = $input.all();
const results = [];
for (const item of items) {
  const content = item.json.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const dept = $('Build Dept Prompt').item.json.department;
  const briefId = $('Build Dept Prompt').item.json.briefId;

  // Quality gate: check minimum output length
  const quality = content.length > 200 ? 'good' : 'insufficient';

  results.push({
    json: {
      department: dept,
      briefId,
      output: content,
      quality,
      outputLength: content.length,
      modelUsed: 'gemini-2.5-flash'
    }
  });
}
return results;
